INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VHH_2025_consolidated', 'VHH', 2025, 'consolidated', 'Doanh nghiệp có nhiều giao dịch phức tạp với các bên liên quan: cho vay và nhận hỗ trợ tài chính từ cá nhân ban lãnh đạo (ông Võ Phi Hùng, ông Nguyễn Anh Tú) với lãi suất 0%/tháng không có tài sản đảm bảo; giao dịch mua bán, thuê xe với các công ty chung Chủ tịch HĐQT và chung quản lý chủ chốt. Đáng chú ý, khoản tạm ứng cho ông Nguyễn Đình Chiến (Chủ tịch HĐQT) lên đến 400 triệu đồng, cùng các khoản mượn/trả tiền phát sinh trong năm hàng tỷ đồng. Các giao dịch này cho thấy sự gắn kết tài chính sâu giữa công ty và ban lãnh đạo, tiềm ẩn rủi ro chiếm dụng vốn.', 'Công ty có khoản vay ngắn hạn 14 tỷ VNĐ tại Agribank Chi nhánh TP. Huế, được đảm bảo bằng quyền sử dụng đất thuê của công ty con (khách sạn tại trung tâm Huế). Đây là tài sản chiến lược bị thế chấp. Tổng nợ phải trả chiếm tỷ trọng cao (51,2 tỷ VNĐ) so với vốn chủ sở hữu (8,1 tỷ VNĐ), tỷ lệ nợ/VCSH lên đến 6,3 lần cho thấy đòn bẩy tài chính rất lớn. Công ty còn lỗ lũy kế âm 71 tỷ VNĐ, vượt xa vốn điều lệ 75 tỷ. Áp lực trả nợ ngắn hạn rất cao khi toàn bộ nợ đều có kỳ hạn dưới 1 năm.', 'Hàng tồn kho chủ yếu là nguyên vật liệu sản xuất bê tông (638 tỷ VNĐ) với giá trị hợp lý, không có trích lập dự phòng giảm giá. Tuy nhiên, chi phí xây dựng cơ bản dở dang 1,7 tỷ VNĐ bao gồm 2 dự án có vấn đề lớn: dự án mỏ đá bị Nhà nước thu hồi giao cho doanh nghiệp khác và dự án Heritage chưa triển khai lại. Hai dự án này chiếm 1,19 tỷ VNĐ nhưng thiếu bằng chứng kiểm toán đầy đủ, tiềm ẩn nguy cơ mất vốn.', 7, 'Công ty Cổ phần Đầu tư Kinh doanh nhà Thành Đạt đang trong tình trạng tài chính khó khăn nghiêm trọng: lỗ lũy kế âm 71 tỷ VNĐ (gấp gần 9 lần vốn chủ sở hữu), ý kiến kiểm toán ngoại trừ với nhiều vấn đề chưa được xác nhận (nợ phải thu 18,8 tỷ quá hạn chưa trích lập dự phòng, khoản phải thu phải trả chưa xác nhận hơn 13,5 tỷ và 6,6 tỷ). Công ty phụ thuộc lớn vào vay ngắn hạn và hỗ trợ tài chính từ ban lãnh đạo. Lĩnh vực kinh doanh chính (sản xuất bê tông) có biên lợi nhuận gộp chỉ ~5,7%, hoạt động khách sạn đã ngừng. Ban lãnh đạo biến động频繁 (nhiều Tổng Giám đốc thay đổi trong năm). Các dự án đầu tư dở dang có nguy cơ mất vốn. Triển vọng đầu tư rất rủi ro.'),
('VHH_2024_consolidated', 'VHH', 2024, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, đáng chú ý là khoản cho Tổng Giám đốc Võ Phi Hùng mượn tiền không lãi suất (hạn mức 4 tỷ đồng) và khoản cho vay có lãi suất với công ty liên quan (Công ty CP Vật liệu Xây dựng Đà Nẵng). Các giao dịch này tuy có quy mô không quá lớn so với tổng tài sản nhưng tiềm ẩn xung đột lợi ích và rủi ro về dòng tiền.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Nợ phải trả chủ yếu là nợ ngắn hạn với nhà cung cấp và các khoản phải trả khác (bao gồm cả khoản hỗ trợ tài chính từ ban lãnh đạo). Tỷ lệ nợ ngắn hạn/Vốn chủ sở hữu ở mức cao (~2.77 lần), tạo áp lực thanh toán. Tuy nhiên, nợ chủ yếu là thương mại và có thể giãn thanh toán.', 'Hàng tồn kho giảm mạnh từ 3,7 tỷ xuống 504 triệu, chủ yếu là nguyên vật liệu. Không có dự phòng giảm giá. Dự án xây dựng dở dang (1,19 tỷ) có rủi ro lớn: một dự án đã bị Nhà nước giao cho doanh nghiệp khác, chi phí giải tỏa đền bù có nguy cơ không thu hồi được.', 6, 'Doanh nghiệp trong tình trạng tài chính khó khăn với vốn chủ sở hữu âm (-66,1 tỷ lợi nhuận chưa phân phối lũy kế). Kiểm toán ngoại trừ do không đối chiếu được khoản phải thu/trả lớn và nghi ngờ khả năng thu hồi nợ phải thu quá hạn. Hoạt động kinh doanh cốt lõi (sản xuất bê tông) có biên lợi nhuận gộp rất thấp (<1%). Ban lãnh đạo có giao dịch cá nhân với công ty (cho vay/mượn tiền) làm tăng rủi ro quản trị.'),
('VHH_2023_consolidated', 'VHH', 2023, 'consolidated', 'Công ty có giao dịch đáng kể với các bên liên quan, đặc biệt là khoản cho vay Công ty CP Vật liệu Xây dựng - Xây lắp và Kinh doanh nhà Đà Nẵng (cổ đông lớn) với lãi suất 8.5%/năm và khoản Tổng Giám đốc Võ Phi Hùng cho Công ty mượn tiền không lãi suất (0%/năm). Các giao dịch thuê xe với Công ty TNHH Đầu tư Dịch vụ 68 cũng có giá trị lớn. Rủi ro trung bình, cần theo dõi tính công bằng và mục đích sử dụng vốn.', 'Nợ phải trả tài chính tập trung ở nợ ngắn hạn (chiếm >99%), chủ yếu là phải trả người bán. Không có vay ngân hàng dài hạn, áp lực trả nợ ngắn hạn cao. Nợ ngắn hạn lớn hơn nhiều so với tiền mặt và khoản phải thu ngắn hạn, cho thấy rủi ro thanh khoản đáng kể.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu, không có dự phòng giảm giá. Có khoản chi phí xây dựng cơ bản dở dang liên quan đến dự án mỏ đá (711 triệu VND) đang có rủi ro do Nhà nước đã giao dự án cho doanh nghiệp khác, khả năng thu hồi không chắc chắn.', 6, 'Công ty đang hoạt động trong tình trạng tài chính khó khăn, với lợi nhuận gộp âm (-2.14 tỷ VND năm 2023), lỗ lũy kế lớn (-61.66 tỷ VND). Nợ ngắn hạn áp đảo tài sản ngắn hạn, tiềm ẩn rủi ro thanh khoản. Kiểm toán đưa ra ý kiến ngoại trừ về nhiều khoản phải thu, phải trả chưa đối chiếu và giá trị hàng tồn kho. Các giao dịch với bên liên quan phức tạp, đặc biệt là khoản cho vay không lãi suất từ Tổng Giám đốc. Điểm rủi ro quản trị ở mức cao (6/10). Doanh nghiệp cần cải thiện hiệu quả kinh doanh và quản lý dòng tiền.'),
('VHH_2023_parent', 'VHH', 2023, 'parent', 'Giao dịch với các bên liên quan bao gồm cho vay không lãi suất (ông Võ Phi Hùng, hạn mức 4 tỷ đồng, lãi suất 0%), thuê tài sản với công ty con và các công ty có chung quản lý. Các khoản cho vay không lãi suất và nợ phải trả lớn với công ty con (hơn 3.9 tỷ đồng) tiềm ẩn rủi ro về chiếm dụng vốn và thiếu minh bạch.', 'Nợ phải trả toàn bộ là ngắn hạn (tổng hơn 34 tỷ đồng), áp lực thanh toán tức thời cao. Công ty đang lỗ lũy kế lớn (hơn 60 tỷ đồng), khả năng trả nợ dựa vào thu hồi công nợ và dòng tiền kinh doanh. Không có nợ dài hạn nhưng rủi ro thanh khoản do tài sản ngắn hạn (khoảng 36.8 tỷ đồng) thấp hơn nợ ngắn hạn.', 'Hàng tồn kho chủ yếu là nguyên liệu vật liệu (hơn 3.6 tỷ đồng) không có dự phòng, nhưng có các khoản trả trước và chi phí phải trả tồn đọng từ năm 2005 (tổng hơn 1.6 tỷ đồng) cho thấy rủi ro thu hồi và đọng vốn. Dự án xây dựng dở dang (hơn 1.1 tỷ đồng) bao gồm dự án mỏ đá đã bị nhà nước giao cho doanh nghiệp khác, khả năng thu hồi chi phí thấp.', 7, 'Công ty đang trong tình trạng tài chính khó khăn với lỗ lũy kế lớn, ý kiến kiểm toán ngoại trừ do các khoản phải thu, phải trả không đối chiếu và hàng tồn kho không kiểm kê. Giao dịch bên liên quan phức tạp, nợ ngắn hạn cao hơn tài sản ngắn hạn. Ban lãnh đạo có xung đột lợi ích (cho vay không lãi suất). Rủi ro quản trị và tài chính ở mức cao, triển vọng đầu tư tiêu cực.'),
('VHH_2022_consolidated', 'VHH', 2022, 'consolidated', 'Rủi ro trung bình. Công ty có giao dịch cho vay với công ty liên quan (Công ty CP Vật liệu xây dựng - Xây lắp và Kinh doanh nhà Đà Nẵng) với lãi suất 8.5%/năm. Tổng giá trị cho vay gốc là 4,088,678,200 VND, nợ lãi phải thu là 2,482,049,800 VND. Dù giao dịch có hợp đồng, việc công ty liên quan này có cùng Chủ tịch HĐQT và nợ gốc đã quá hạn nhưng vẫn ghi nhận lãi dự thu là điểm cần lưu ý. Các giao dịch khác (thuê xe) có quy mô nhỏ.', 'Rủi ro thấp. Tổng nợ vay ngắn hạn chỉ 243,250,000 VND, chiếm tỷ trọng rất nhỏ trong tổng tài sản (dưới 0.5%). Công ty chỉ vay từ một ngân hàng với lãi suất ban đầu 10.4%/năm, sau đó thả nổi. Áp lực trả nợ gốc và lãi vay hàng năm không đáng kể so với dòng tiền kinh doanh. Tuy nhiên, doanh nghiệp đang lỗ lũy kế lớn (-55,742,739,981 VND) làm suy giảm nền tảng vốn chủ sở hữu.', 'Rủi ro thấp. Hàng tồn kho chủ yếu là nguyên vật liệu cho sản xuất bê tông (hơn 99%), không có dự phòng giảm giá, không có hàng tồn kho ứ đọng hay cầm cố. Dự án xây dựng dở dang có tổng giá trị ~1.47 tỷ VND, trong đó dự án mỏ đá (711 triệu VND) có rủi ro thu hồi do dự án đã được giao cho đơn vị khác, nhưng giá trị không lớn.', 6, 'Doanh nghiệp đang trong giai đoạn khó khăn tài chính, với lợi nhuận sau thuế âm liên tục và lỗ lũy kế tích lũy lớn, chủ yếu do hoạt động kinh doanh cốt lõi (bê tông) lỗ gộp. Ý kiến kiểm toán ngoại trừ cho thấy một số vấn đề quản trị và nợ phải thu, phải trả chưa được đối chiếu, cùng với dự án đầu tư có rủi ro. Cấu trúc tài chính cơ bản an toàn về nợ vay nhưng nền tảng vốn chủ sở hữu bị xói mòn. Công ty cần cải thiện hiệu quả kinh doanh, xử lý các khoản nợ khó đòi và dự án đầu tư rủi ro.'),
('VHH_2019_consolidated', 'VHH', 2019, 'consolidated', 'Giao dịch với bên liên quan (Công ty CP Vật liệu Xây dựng - Xây lắp và Kinh doanh nhà Đà Nẵng) bao gồm cho vay, cho thuê và thu hồi nợ. Các giao dịch này có quy mô tương đối lớn so với quy mô tài sản ngắn hạn của công ty. Tuy nhiên, không có thông tin chi tiết về điều khoản giao dịch, lãi suất cho vay và lịch trình trả nợ, tạo ra rủi ro về tính minh bạch và khả năng thu hồi.', 'Nợ vay tập trung vào một chủ nợ duy nhất là Ngân hàng TMCP Sài Gòn - Hà Nội (SHB) với lãi suất ban đầu ưu đãi nhưng sau đó thả nổi. Tổng nợ vay ngắn hạn và dài hạn là 3.881.650.000 VND, áp lực trả nợ cao khi công ty đang kinh doanh thua lỗ. Tài sản thế chấp là TSCĐ phục vụ sản xuất kinh doanh cốt lõi.', 'Hàng tồn kho chủ yếu là nguyên vật liệu và công cụ dụng cụ, không có dự phòng giảm giá. Tuy nhiên, có hai dự án xây dựng dở dang đã tồn tại từ nhiều năm trước (không ghi rõ thời gian bắt đầu) và không có phát sinh chi phí trong năm, cho thấy dự án có thể bị đình trệ, tiềm ẩn nguy cơ đọng vốn.', 6, 'Công ty có sức khỏe tài chính yếu kém với lỗ lũy kế lớn (-45,56 tỷ VND) và lợi nhuận năm 2019 âm. Dòng tiền kinh doanh dương nhưng chủ yếu do giảm khoản phải thu, không bền vững. Cơ cấu nợ tập trung vào một ngân hàng với lãi suất có thể tăng. Có giao dịch đáng kể với bên liên quan và một số khoản mục nợ phải trả/trả trước cũ từ năm 2005 chưa được xử lý dứt khoát, làm tăng rủi ro quản trị và minh bạch. Ý kiến kiểm toán ngoại trừ do công ty tự ý điều chỉnh giảm khấu hao, làm sai lệch kết quả kinh doanh thực tế.'),
('VHH_2020_consolidated', 'VHH', 2020, 'consolidated', 'Có giao dịch cho vay với công ty con (15 triệu) và công ty liên quan chung Chủ tịch HĐQT (4,37 tỷ) với lãi suất 8.5%/năm. Giao dịch thuế tài sản với công ty con (1,5 tỷ) có thể là thuế đất. Các khoản phải thu từ cho vay lớn và đã quá hạn, khả năng thu hồi không rõ ràng.', 'Nợ vay tập trung tại Ngân hàng SHB Chi nhánh Huế với lãi suất biến động và áp lực trả nợ ngắn hạn cao (nợ ngắn hạn 26,5 tỷ so với tiền mặt chỉ 1,3 tỷ). Tỷ lệ nợ/VCSH là 0.84 lần, đòn bẩy tài chính lớn. Tài sản thế chấp chính là TSCĐ hữu hình.', 'Hàng tồn kho chủ yếu là nguyên vật liệu (2,48 tỷ), không có dự phòng giảm giá. Dự án xây dựng dở dang tồn tại lâu năm (dự án khai thác mỏ đá đã bị Nhà nước giao cho đơn vị khác), có nguy cơ đọng vốn và không tạo ra giá trị.', 6, 'Công ty hoạt động trong lĩnh vực xây dựng và bất động sản đang gặp nhiều khó khăn. Kết quả kinh doanh thua lỗ (lỗ lũy kế 46,4 tỷ), dòng tiền kinh doanh dương nhưng chủ yếu từ giảm phải thu. Kiểm toán có ý kiến ngoại trừ về nợ phải thu khó đòi và dự án khai thác mỏ đá. Nợ vay cao, áp lực thanh khoản lớn, hàng tồn kho và dự án dở dang tiềm ẩn rủi ro. Triển vọng đầu tư kém khả quan.'),
('VHH_2018_consolidated', 'VHH', 2018, 'consolidated', 'Các giao dịch với công ty con Công ty CP Đầu tư Route Inn Huế bao gồm cho thuê tài sản và góp vốn bằng TSCĐ/CCDC. Giá trị góp vốn bằng TSCĐ lớn (8.557 tỷ) nhưng là hoạt động đầu tư chiến lược vào công ty con. Không phát hiện dấu hiệu chuyển giá hay rút vốn bất thường.', 'Nợ vay tập trung tại một ngân hàng (SHB) với lãi suất ban đầu 10,4%/năm. Tổng nợ vay 4,73 tỷ VND so với vốn chủ sở hữu 36,06 tỷ VND, tỷ lệ nợ/vốn chủ sở hữu chỉ ~0.13 lần, ở mức an toàn. Thời hạn vay 60 tháng, áp lực trả nợ ngắn hạn không đáng kể.', 'Hàng tồn kho tăng mạnh từ 971 triệu lên 1.852 triệu nhưng chủ yếu là nguyên vật liệu phục vụ sản xuất bê tông, không có hàng ứ đọng hay kém phẩm chất. Dự án xây dựng dở dang giảm từ 1.981 triệu xuống 1.189 triệu, cho thấy tiến độ triển khai dự án đang được cải thiện.', 5, 'Doanh nghiệp có ý kiến kiểm toán ngoại trừ do trích lập thiếu dự phòng phải thu khó đòi 1,09 tỷ VND. Tuy nhiên, tỷ lệ nợ vay thấp (0.13 lần), hoạt động kinh doanh chính (sản xuất bê tông) tăng trưởng doanh thu mạnh. Hàng tồn kho và dự án dở dang ở mức kiểm soát được. Cần lưu ý các khoản trả trước cho người bán và chi phí phải trả tồn tại từ năm 2005 chưa được xử lý dứt điểm.'),
('VHH_2019_parent', 'VHH', 2019, 'parent', 'Có giao dịch với công ty con và công ty đầu tư, trong đó có khoản cho vay lớn cho công ty đầu tư (Công ty CP Vật liệu xây dựng - Xây lắp và Kinh doanh nhà Đà Nẵng) với số dư 4.580.678.200 đồng. Các giao dịch thuê tài sản, thuê xe, thu hồi nợ vay có giá trị nhưng không quá lớn so với quy mô công ty. Tuy nhiên, cần lưu ý khoản cho vay này có thể ảnh hưởng đến thanh khoản nếu không thu hồi được.', 'Nợ vay chủ yếu tập trung tại Ngân hàng TMCP Sài Gòn - Hà Nội với tổng dư nợ 3.881.650.000 đồng, chiếm khoảng 11% vốn chủ sở hữu. Lãi suất vay biến đổi theo ngân hàng. Áp lực trả nợ ngắn hạn ở mức vừa phải, nợ dài hạn còn lại 1.410.850.000 đồng đáo hạn vào năm 2023. Công ty có tài sản cố định thế chấp cho khoản vay.', 'Hàng tồn kho chủ yếu là nguyên liệu, vật liệu phục vụ sản xuất bê tông, không có dự phòng giảm giá. Dự án dở dang bao gồm dự án khách sạn và khai thác mỏ đá với tổng giá trị 1.189.545.626 đồng, chưa rõ tiến độ triển khai, có thể tích tụ chi phí lâu dài.', 6, 'Công ty lỗ năm 2019 do giá vốn tăng cao và chi phí tài chính tăng. Có vấn đề kiểm toán ngoại trừ liên quan đến thay đổi thời gian khấu hao. Nợ vay ở mức thấp nhưng có khoản phải thu lớn cho bên liên quan. Hàng tồn kho và dự án dở dang ở mức hợp lý. Tuy nhiên, công ty còn tồn đọng nhiều vấn đề nội bộ, cần theo dõi khả năng hoạt động liên tục và quản trị rủi ro.'),
('VHG_2025_consolidated', 'VHG', 2025, 'consolidated', 'Có khoản tạm ứng cho Chủ tịch HĐQT 4,4 tỷ VND và khoản phải thu từ Công ty CP Tây Bà Nà (liên kết) 7,3 tỷ VND đã trích lập dự phòng 100%. Các giao dịch này cho thấy rủi ro chiếm dụng vốn và khả năng thu hồi thấp.', 'Công ty có nợ quá hạn thuế nhà nước 4,2 tỷ VND, phản ánh áp lực tài chính nghiêm trọng. Tổng nợ ngắn hạn 6,9 tỷ VND so với tài sản ngắn hạn 4,8 tỷ VND cho thấy mất cân đối thanh khoản. Không có nợ dài hạn nhưng dòng tiền hoạt động kinh doanh âm liên tục.', 'Chi phí sản xuất kinh doanh dở dang 2,3 tỷ VND đã trích lập dự phòng 100%, cho thấy tài sản không có giá trị thu hồi. Hàng tồn kho không tạo ra doanh thu.', 8, 'Công ty trong tình trạng tài chính cực kỳ khó khăn: lỗ lũy kế 1.394 tỷ VND chiếm 93% vốn điều lệ, không có doanh thu, nợ thuế quá hạn, dòng tiền hoạt động kinh doanh âm. Ban lãnh đạo đang thực hiện tái cơ cấu nhưng triển vọng phục hồi rất rủi ro. Ý kiến kiểm toán ngoại trừ về giá trị khoản đầu tư liên kết 241,8 tỷ VND.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VHH_2021_consolidated', 'VHH', 2021, 'consolidated', 'Giao dịch với Công ty CP Vật liệu xây dựng - Xây lắp và Kinh doanh nhà Đà Nẵng (cùng Chủ tịch HĐQT) bao gồm khoản cho vay 4.232.678.200 đồng và lãi phải thu 2.128.158.800 đồng. Một số khoản nợ phải thu đã quá hạn thanh toán, có rủi ro về khả năng thu hồi. Kiểm toán viên không thể xác định tính hiện hữu và khả năng thu hồi của các khoản nợ này.', 'Nợ vay chủ yếu tại Ngân hàng TMCP Sài Gòn – Hà Nội với lãi suất cao 10.4%/năm, áp lực trả nợ ngắn hạn 583.800.000 đồng. Tổng nợ vay 827.050.000 đồng so với vốn chủ sở hữu 29.014.159.548 đồng, tỷ lệ nợ/VCSH thấp (0.028), nhưng chi phí lãi vay đáng kể trong bối cảnh doanh nghiệp lỗ.', 'Hàng tồn kho tăng mạnh từ 2.513.626.891 đồng lên 4.558.939.483 đồng, chủ yếu do nguyên vật liệu tăng. Không có dự phòng giảm giá, không có hàng ứ đọng. Dự án xây dựng dở dang 1.189.545.626 đồng, trong đó dự án mỏ đá có vấn đề pháp lý, có thể ảnh hưởng đến thu hồi vốn.', 7, 'Doanh nghiệp hoạt động trong lĩnh vực xây dựng và bất động sản, chịu ảnh hưởng nặng nề bởi đại dịch Covid-19, lỗ sau thuế 2.075.921.501 đồng năm 2021. Lỗ lũy kế lớn (-50.154.549.068 đồng) ăn vào vốn chủ sở hữu. Nợ vay không quá cao nhưng áp lực lãi vay. Giao dịch với bên liên quan và các khoản phải thu khó đòi là rủi ro lớn. Kiểm toán đưa ra ý kiến ngoại trừ do một số khoản nợ phải thu và trả chưa được đối chiếu, xác nhận. Cần cải thiện quản trị rủi ro và thu hồi công nợ.'),
('VHG_2024_consolidated', 'VHG', 2024, 'consolidated', 'Công ty có khoản tạm ứng lớn cho Chủ tịch HĐQT (3,3 tỷ VND) và khoản phải thu từ công ty liên kết Tây Bà Nà (hơn 7,3 tỷ VND), tiềm ẩn rủi ro chiếm dụng vốn. Đồng thời, đầu tư vào công ty liên kết có dự phòng tổn thất lớn.', 'Công ty không có nợ vay tài chính ngắn hạn hay dài hạn. Tuy nhiên, có khoản nợ thuế quá hạn nộp ngân sách nhà nước 8,6 tỷ VND tồn tại từ đầu năm và chưa được thanh toán, cho thấy áp lực thanh toán thuế.', 'Hàng tồn kho duy nhất là chi phí sản xuất kinh doanh dở dang với giá trị sổ sách 6,7 tỷ VND đã được trích lập dự phòng giảm giá toàn bộ 100%, phản ánh việc thu hồi gần như không thể, rủi ro đọng vốn đã được ghi nhận.', 7, 'Công ty hoạt động trong lĩnh vực trồng cây cao su nhưng không phát sinh doanh thu bán hàng trong kỳ, chủ yếu phát sinh chi phí tài chính (dự phòng đầu tư) và chi phí quản lý. Lỗ lũy kế lên đến 92,63% vốn điều lệ, kết hợp với nợ thuế quá hạn và ý kiến kiểm toán ngoại trừ về dự phòng đầu tư vào công ty liên kết, cho thấy sức khỏe tài chính rất yếu và nghi ngờ lớn về khả năng hoạt động liên tục. Cấu trúc cổ đông tập trung vào Chủ tịch HĐQT, ban điều hành kiêm nhiệm nhiều vị trí, tiềm ẩn rủi ro quản trị.'),
('VHG_2021_consolidated', 'VHG', 2021, 'consolidated', 'Giao dịch cho vay cá nhân với Chủ tịch HĐQT (364 triệu đồng) không rõ mục đích và lãi suất, có dấu hiệu chiếm dụng vốn. Công ty liên kết Tây Bà Nà cũng phát sinh giao dịch nhận nợ hộ.', 'Không có nợ vay tài chính từ ngân hàng. Nợ phải trả chủ yếu là nợ thuế quá hạn 10.7 tỷ đồng và nợ phải trả thương mại nhỏ. Áp lực trả nợ thuế ngân sách nhà nước rất lớn.', 'Hàng tồn kho dở dang (gần 8.9 tỷ đồng) đã trích lập dự phòng giảm giá 100%, cho thấy khoản đầu tư này không có khả năng thu hồi, rủi ro mất vốn hoàn toàn.', 8, 'Doanh nghiệp trong tình trạng tài chính rất yếu kém: không có hoạt động kinh doanh cốt lõi, lỗ lũy kế chiếm 90.64% vốn điều lệ, nợ thuế ngân sách nhà nước quá hạn lớn, giao dịch bên liên quan có dấu hiệu bất thường, ý kiến kiểm toán ngoại trừ. Rủi ro hoạt động liên tục rất cao.'),
('VHG_2023_consolidated', 'VHG', 2023, 'consolidated', 'Công ty có giao dịch lớn với các công ty liên kết, trong đó khoản đầu tư vào Công ty Cổ phần Tây Bà Nà có giá trị 120 tỷ đồng đã trích lập dự phòng 75,8 tỷ đồng và khoản đầu tư vào Công ty Cổ phần Sản xuất Ứng dụng Công nghệ Cao Thái Sơn 121,8 tỷ đồng đã trích lập dự phòng 28,7 tỷ đồng. Kiểm toán viên không thể thu thập đủ bằng chứng về giá trị dự phòng đầu tư vào Tây Bà Nà. Chủ tịch HĐQT có khoản tạm ứng 1,8 tỷ đồng và khoản phải trả 205 triệu đồng. Công ty đã bán nợ khó đòi 131,8 tỷ đồng cho cá nhân ông Ngô Văn Quốc với giá chỉ 3,3 tỷ đồng, cho thấy dấu hiệu thoái vốn giá rẻ.', 'Công ty không có nợ vay ngân hàng hay trái phiếu. Tuy nhiên, nợ quá hạn thuế phải nộp Ngân sách Nhà nước lên đến 8,6 tỷ đồng bao gồm thuế nhà đất 3,5 tỷ và phí lệ phí 5,2 tỷ. Nợ phải trả người bán 814 triệu đồng cũng đã quá hạn thanh toán. Tổng nợ ngắn hạn 11,3 tỷ đồng so với vốn chủ sở hữu 138,9 tỷ đồng, tỷ lệ nợ/vốn thấp 0,08 lần nhưng áp lực thanh toán thuế ngân sách là đáng lo ngại.', 'Hàng tồn kho duy nhất là chi phí sản xuất kinh doanh dở dang 6,7 tỷ đồng đã được trích lập dự phòng 100%, cho thấy toàn bộ giá trị hàng tồn kho không còn khả năng thu hồi. Công ty hoạt động trong lĩnh vực trồng cây cao su nhưng không phát sinh doanh thu trong năm, hoạt động sản xuất kinh doanh đình trệ nghiêm trọng. Dự phòng giảm giá hàng tồn kho giảm từ 8,9 tỷ xuống 6,7 tỷ do hoàn nhập một phần.', 9, 'Công ty Cổ phần Đầu tư và Phát triển Việt Trung Nam đang trong tình trạng tài chính cực kỳ nghiêm trọng. Lỗ lũy kế 1.387 tỷ đồng chiếm 92,5% vốn điều lệ 1.500 tỷ đồng, nợ thuế quá hạn 8,6 tỷ đồng. Công ty không phát sinh doanh thu trong năm 2023, chỉ có 2 nhân viên, toàn bộ hàng tồn kho trích lập dự phòng 100%. Công ty đã bán nợ khó đòi 131,8 tỷ đồng cho cá nhân với giá 3,3 tỷ đồng. Đầu tư vào công ty liên kết 241,8 tỷ đồng đã trích lập dự phòng 104,4 tỷ đồng. Kiểm toán có ý kiến ngoại trừ và nhấn mạnh về khả năng hoạt động liên tục. Công ty cần tái cơ cấu mạnh mẽ để có thể tiếp tục hoạt động.'),
('VHG_2022_consolidated', 'VHG', 2022, 'consolidated', 'Công ty có giao dịch với các công ty liên kết và thành viên quản lý, nhưng không có giao dịch mua bán lớn trong năm. Khoản phải thu từ Công ty Cổ phần Tây Bà Nà là 7.3 tỷ VND, và đầu tư vào các công ty liên kết đã trích lập dự phòng lớn, cho thấy rủi ro tài chính cao từ các khoản đầu tư.', 'Công ty không có nợ vay ngân hàng, nhưng nợ thuế quá hạn 10.77 tỷ VND và các khoản phải trả khác. Áp lực thanh toán ngắn hạn do lỗ lũy kế và thiếu dòng tiền kinh doanh.', 'Hàng tồn kho là chi phí sản xuất kinh doanh dở dang đã được trích lập dự phòng toàn bộ, rủi ro thấp nhưng phản ánh hoạt động kinh doanh đình trệ.', 8, 'Doanh nghiệp trong tình trạng tài chính khó khăn với lỗ lũy kế vượt vốn điều lệ, không có doanh thu, nợ thuế quá hạn. Khả năng hoạt động liên tục bị nghi ngờ. Đầu tư vào công ty liên kết rủi ro cao với dự phòng lớn. Triển vọng tiêu cực.'),
('VHF_2024_consolidated', 'VHF', 2024, 'consolidated', 'Công ty có giao dịch bán hàng lớn với công ty mẹ (Tổng Công ty Lương thực Miền Bắc) và mua hàng từ các công ty cùng mẹ. Các giao dịch này được thực hiện theo giá và điều khoản thị trường thông thường. Tuy nhiên, doanh thu từ bên liên quan chiếm tỷ trọng đáng kể trong tổng doanh thu (khoảng 6%), tạo ra sự phụ thuộc vào hệ sinh thái nội bộ. Ngoài ra, khoản phải thu từ công ty TNHH Thương mại và Dịch vụ Đại Phước (đối tác hợp tác kinh doanh) khoảng 59,9 tỷ VND đã quá hạn thanh toán nhưng chưa được ghi nhận điều chỉnh, tiềm ẩn rủi ro thu hồi.', 'Nợ vay ngắn hạn tăng mạnh từ 28,8 tỷ lên 82,4 tỷ VND, chủ yếu vay bổ sung vốn lưu động tại các ngân hàng lớn (BIDV, Agribank). Tỷ lệ nợ ngắn hạn/vốn chủ sở hữu ở mức ~0.56 lần, áp lực trả nợ trong ngắn hạn cao. Công ty sử dụng tiền gửi có kỳ hạn làm tài sản thế chấp cho một phần khoản vay. Lãi suất vay biến động theo thị trường, chưa có thông tin chi tiết về lãi suất trung bình.', 'Hàng tồn kho tăng nhẹ so với đầu năm, với dự phòng giảm giá tăng đáng kể (từ 44,5 triệu lên 1,29 tỷ VND), cho thấy một phần hàng hóa có nguy cơ mất giá trị. Dự án xây dựng dở dang (9A Vĩnh Tuy, Km10 Văn Điển) với tổng giá trị 6,5 tỷ VND đã bị tạm dừng triển khai nhiều năm theo quy định xử lý tài sản công, tiềm ẩn rủi ro đọng vốn và giảm giá trị.', 5, 'Công ty có cấu trúc tài chính với tỷ lệ nợ vay ngắn hạn tăng mạnh, chủ yếu phục vụ hoạt động kinh doanh thương mại lương thực. Hoạt động kinh doanh cốt lõi tạo lợi nhuận gộp nhưng biên lợi nhuận mỏng (~4%). Các khoản đầu tư tài chính và bất động sản đầu tư mang lại nguồn doanh thu tài chính ổn định. Tuy nhiên, Công ty đối mặt với một số rủi ro: sự phụ thuộc vào giao dịch với công ty mẹ và các công ty cùng mẹ; áp lực trả nợ ngắn hạn lớn; một khoản phải thu lớn từ hợp tác kinh doanh đã quá hạn; và các dự án xây dựng dở dang bị đình trệ. Khả năng hoạt động liên tục không bị nghi ngờ nhưng cần theo dõi sát tình hình thu hồi công nợ và tiến độ triển khai các dự án bất động sản.'),
('VHF_2021_consolidated', 'VHF', 2021, 'consolidated', 'Công ty có mối quan hệ kinh doanh phức tạp và giá trị lớn với công ty mẹ Tổng Công ty Lương thực Miền Bắc (mua bán hàng hóa hàng chục tỷ đồng). Mặc dù các giao dịch này thuộc hoạt động kinh doanh cốt lõi, song việc tập trung giao dịch lớn với một bên liên quan chính tạo ra rủi ro về tính độc lập và khả năng bị phụ thuộc. Kiểm toán viên đã nhấn mạnh các vấn đề về dự án dở dang liên quan đến bên liên quan.', 'Nợ vay ngắn hạn tăng mạnh từ 12.1 tỷ VND lên 54.0 tỷ VND trong năm, chủ yếu từ BIDV. Áp lực trả nợ ngắn hạn cao. Một phần nợ được đảm bảo bằng tiền gửi, còn lại không có tài sản đảm bảo. Tuy nhiên, tỷ lệ nợ thuần/vốn chủ sở hữu vẫn ở mức 20%, cho thấy đòn bẩy tài chính vừa phải.', 'Tồn kho tăng vọt từ 10.0 tỷ VND lên 29.5 tỷ VND, chủ yếu là ''Hàng hóa'' và ''Hàng mua đang đi đường''. Điều này có thể cho thấy hàng hóa bị ứ đọng hoặc chu kỳ kinh doanh bị kéo dài. Dự án xây dựng dở dang (chi phí xây dựng cơ bản) có giá trị 6.5 tỷ VND, là trọng điểm của ý kiến kiểm toán ngoại trừ do chưa đánh giá được tổn thất.', 7, 'Doanh nghiệp có quy mô vốn chủ sở hữu lớn (215 tỷ VND) nhưng hiệu quả kinh doanh thấp, biên lợi nhuận gộp chỉ khoảng 3.4%. Công ty phải nhận ý kiến kiểm toán ngoại trừ do không đánh giá được tổn thất từ dự án dở dang, cho thấy vấn đề trong công tác quản lý dự án và đánh giá tài sản. Giao dịch với bên liên quan lớn, nợ vay tăng mạnh và tồn kho tăng vọt là các điểm rủi ro. Ban lãnh đạo có thay đổi, Chủ tịch HĐQT mới. Triển vọng đầu tư không rõ ràng và tiềm ẩn nhiều rủi ro.'),
('VHF_2025_consolidated', 'VHF', 2025, 'consolidated', 'Công ty có quan hệ kinh doanh chặt chẽ với công ty mẹ Tổng Công ty Lương thực Miền Bắc và các công ty con cùng hệ thống, bao gồm mua bán hàng hóa với quy mô lớn. Các giao dịch chủ yếu thuộc hoạt động thương mại cốt lõi, chưa thấy dấu hiệu bất thường. Đáng lưu ý là khoản phải thu 59,95 tỷ VND từ Công ty TNHH Thương mại và Dịch vụ Đại Phước theo hợp đồng hợp tác kinh doanh 231 Cầu Giấy đã quá hạn thanh toán từ năm 2020, dự án chưa triển khai được do vướng mắc đất đai và chưa được ghi nhận điều chỉnh nào trong BCTC. Đây là rủi ro lớn về chiếm dụng vốn từ đối tác liên quan.', 'Nợ vay ngắn hạn tăng mạnh từ 82,4 tỷ lên 119,4 tỷ VND (tăng 45%), chủ yếu tập trung tại BIDV Tây Hồ (81,2 tỷ) và Agribank Hà Nội (35,8 tỷ). Tỷ lệ nợ thuần/Vốn chủ sở hữu tăng từ 31,66% lên 44,05%. Có khoản vay cá nhân 2,39 tỷ VND lãi suất 0-5%/năm không có tài sản đảm bảo, tiềm ẩn rủi ro đáo hạn ngắn hạn. Công ty có lỗ lũy kế 19,46 tỷ VND nhưng chưa ghi nhận thuế TNDN hoãn lại. Dòng tiền từ hoạt động kinh doanh âm 54,78 tỷ VND cho thấy áp lực thanh toán thực tế.', 'Hàng tồn kho tăng từ 77,75 tỷ lên 87,68 tỷ VND, trong đó chi phí sản xuất kinh doanh dở dang chiếm 14,34 tỷ VND (gồm 3 dự án xây dựng tại Phú Thọ và Việt Trì mới phát sinh trong năm). Dự phòng giảm giá hàng tồn kho chỉ chiếm 2,3% giá gốc, mức trích lập thấp. Các dự án xây dựng dở dang chưa rõ tiến độ hoàn thành và bàn giao. Chi phí xây dựng cơ bản dở dang 6,51 tỷ VND tại Vĩnh Tuy và Văn Điển đã tồn tại từ năm trước, đang chờ phê duyệt triển khai.', 5, 'Doanh nghiệp có quy mô vốn chủ sở hữu lớn 231 tỷ VND và đã có lãi trở lại năm 2025 (6,94 tỷ VND) sau nhiều năm lỗ lũy kế. Tuy nhiên, tồn tại nhiều rủi ro đáng chú ý: (1) Dòng tiền hoạt động kinh doanh âm nặng (-54,78 tỷ VND) phản ánh vốn bị chiếm dụng trong các khoản phải thu và hàng tồn kho; (2) Khoản phải thu 59,95 tỷ VND từ Đại Phước kéo dài nhiều năm chưa được xử lý; (3) Quyền sử dụng đất tại Bình Dương nguyên giá 5,56 tỷ VND chưa có Giấy chứng nhận; (4) Nợ vay ngắn hạn tăng mạnh. Công ty dựa vào dòng tiền từ hoạt động đầu tư (thu lãi tiền gửi, cho vay) và hoạt động tài chính (vay mới trả nợ cũ) để bù đắp. Triển vọng trung hạn cần được đánh giá thận trọng.'),
('VHF_2022_consolidated', 'VHF', 2022, 'consolidated', 'Giao dịch với công ty mẹ và các công ty cùng hệ thống chiếm tỷ trọng lớn trong cả mua và bán. Có khoản phải thu từ Công ty TNHH Thương mại và Dịch vụ Đại Phước (không phải bên liên quan theo danh sách) trị giá 59,95 tỷ VND đã quá hạn thanh toán từ 30/12/2020 nhưng chưa được thanh toán và chưa trích lập dự phòng, đây là rủi ro tín dụng đáng kể.', 'Nợ vay ngắn hạn tập trung tại 3 ngân hàng lớn (BIDV, Agribank) với tổng trị giá gần 57 tỷ VND, tất cả đều không có tài sản đảm bảo. Áp lực trả nợ trong ngắn hạn cao do toàn bộ nợ đều đáo hạn trong 6-12 tháng. Công ty phụ thuộc vào việc đảo nợ liên tục.', 'Hàng tồn kho giảm từ 29,5 tỷ xuống 22,2 tỷ VND, chủ yếu do giảm hàng hóa và hàng mua đang đi đường. Hai dự án xây dựng dở dang (9A Vĩnh Tuy và Số 10 Văn Điền) với tổng giá trị 6,5 tỷ VND đã dừng triển khai từ nhiều năm trước, đang chờ quyết định của cơ quan chức năng, chưa trích lập dự phòng.', 7, 'Công ty có hoạt động kinh doanh cốt lõi là lương thực và bất động sản cho thuê. Tuy nhiên, cấu trúc tài chính có nhiều rủi ro: nợ vay ngắn hạn lớn không có tài sản đảm bảo, khoản phải thu quá hạn lớn chưa trích lập dự phòng, dự án dở dang đình trệ nhiều năm. Kiểm toán viên có ý kiến nhấn mạnh về các vấn đề này. Ban lãnh đạo có biến động nhân sự trong năm. Công ty có lỗ lũy kế tính thuế chưa sử dụng 11,2 tỷ VND. Khả năng hoạt động liên tục được duy trì nhưng áp lực tài chính lớn.'),
('VHF_2023_consolidated', 'VHF', 2023, 'consolidated', 'Công ty có giao dịch mua bán hàng hóa với công ty mẹ và các công ty cùng công ty mẹ với giá trị lớn, nhưng theo thông tin công ty, các giao dịch được thực hiện theo giá thị trường. Tuy nhiên, Công ty có khoản phải thu 59,9 tỷ VND từ hoạt động hợp tác kinh doanh với Công ty TNHH Thương mại và Dịch vụ Đại Phước đã quá hạn thanh toán (theo hợp đồng là không muộn hơn ngày 30/12/2020), tạo ra rủi ro chiếm dụng vốn.', 'Nợ vay ngắn hạn giảm mạnh từ 56,9 tỷ VND xuống còn 28,8 tỷ VND, tỷ lệ nợ/VCSH là 0,44 lần (trên tổng nợ phải trả/VCSH), cho thấy đòn bẩy tài chính ở mức an toàn. Tuy nhiên, chi phí lãi vay tăng mạnh từ 2,8 tỷ lên 8,0 tỷ VND, phản ánh áp lực lãi suất trong bối cảnh Công ty tăng cường vay vốn lưu động. Các khoản vay chủ yếu là tín chấp hoặc thế chấp bằng tiền gửi có kỳ hạn.', 'Hàng tồn kho tăng mạnh từ 47,9 tỷ lên 73,8 tỷ VND, chủ yếu do hàng hóa tăng 30 tỷ VND. Công ty chỉ trích lập dự phòng giảm giá 44,5 triệu VND cho hàng hóa, tỷ lệ trích lập rất thấp (<0,1%). Hai dự án xây dựng dở dang (6,5 tỷ VND) đã kéo dài nhiều năm chờ phê duyệt, có rủi ro đọng vốn.', 5, 'Doanh nghiệp có kết quả kinh doanh tăng trưởng (lợi nhuận sau thuế tăng 16%), dòng tiền từ hoạt động kinh doanh âm do tăng mạnh hàng tồn kho và khoản phải thu. Công ty có cơ cấu tài chính an toàn với tỷ lệ nợ thấp, nhưng rủi ro đến từ: (1) khoản phải thu lớn từ hợp tác kinh doanh có dấu hiệu khó đòi, (2) hàng tồn kho tăng nhanh và dự phòng thấp, (3) dự án xây dựng dở dang chờ phê duyệt nhiều năm. Ban lãnh đạo nhất quán, kiểm toán đưa ra ý kiến chấp nhận toàn phần có nhấn mạnh các vấn đề trên.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VHF_2020_consolidated', 'VHF', 2020, 'consolidated', 'Công ty có giao dịch với công ty mẹ (Tổng Công ty Lương thực Miền Bắc) qua việc chi trả cổ tức và có khoản đầu tư vào công ty liên kết (Công ty TNHH FTC - Tungshing). Ngoài ra, có khoản tạm ứng lớn cho cá nhân ông Nguyễn Văn Toán (ủy viên HĐQT) để thực hiện dự án. Tuy nhiên, quy mô giao dịch không bất thường và phục vụ mục đích kinh doanh thông thường.', 'Nợ vay chủ yếu là ngắn hạn tại các ngân hàng lớn (BIDV, Agribank) với lãi suất theo thỏa thuận và không có tài sản đảm bảo. Áp lực trả nợ thấp do tỷ lệ nợ trên vốn chủ sở hữu chỉ khoảng 0.05 lần. Một khoản vay cá nhân lãi suất 0% cũng giảm áp lực chi phí lãi vay.', 'Công ty không có hàng tồn kho thông thường (nguyên vật liệu, thành phẩm) mà chỉ có chi phí xây dựng cơ bản dở dang cho hai công trình xây dựng. Giá trị tương đối nhỏ và không có trích lập dự phòng, cho thấy rủi ro đọng vốn thấp.', 4, 'Doanh nghiệp có cấu trúc tài chính lành mạnh, nợ vay thấp, dòng tiền hoạt động kinh doanh dương. Lợi nhuận gộp giảm so với năm trước nhưng vẫn ở mức dương. Ban lãnh đạo ổn định, không có giao dịch đáng ngờ với bên liên quan. Tuy nhiên, hoạt động kinh doanh chính (bán buôn lương thực) đang thu hẹp doanh thu, cần theo dõi triển vọng tăng trưởng.'),
('VHF_2019_consolidated', 'VHF', 2019, 'consolidated', 'Giao dịch với bên liên quan, đặc biệt là công ty mẹ và các công ty cùng thành viên BGĐ, có giá trị lớn và là hoạt động kinh doanh thông thường. Không thấy dấu hiệu bất thường rõ ràng, nhưng cần theo dõi vì tần suất giao dịch cao.', 'Nợ vay ngắn hạn tập trung tại các ngân hàng lớn với tổng số dư khoảng 29.6 tỷ VND, không có tài sản đảm bảo. Tỷ lệ nợ trên vốn chủ sở hữu thấp (khoảng 10%), áp lực trả nợ ngắn hạn không đáng kể.', 'Hàng tồn kho giảm mạnh từ 42.3 tỷ xuống 27.5 tỷ VND, chủ yếu là hàng hóa thành phẩm, không trích lập dự phòng. Điều này có thể cho thấy luân chuyển hàng tồn kho tốt, nhưng cần kiểm tra tính thanh khoản của hàng hóa.', 4, 'Doanh nghiệp có sức khỏe tài cơ bản ổn định với tỷ lệ nợ thấp, dòng tiền kinh doanh âm nhưng được bù đắp bằng hoạt động đầu tư và tài chính. Lợi nhuận giảm so với năm trước. Quản trị rủi ro ở mức trung bình, cần cải thiện hiệu quả hoạt động kinh doanh cốt lõi.'),
('VHF_2018_consolidated', 'VHF', 2018, 'consolidated', 'Giao dịch mua bán với công ty mẹ Tổng Công ty Lương thực Miền Bắc có giá trị lớn (bán 32.259 tỷ, mua 5.009 tỷ), tuy nhiên thuộc hoạt động kinh doanh chính lương thực, chưa thấy dấu hiệu chuyển giá bất thường. Tuy nhiên, mức độ tập trung cao vào công ty mẹ có thể tạo rủi ro phụ thuộc.', 'Nợ vay ngắn hạn chủ yếu từ các ngân hàng thương mại lớn với lãi suất không cố định, được đảm bảo bằng uy tín công ty. Tổng nợ vay ngắn hạn 31.96 tỷ, trong khi tiền mặt và đầu tư ngắn hạn lớn (khoảng 118 tỷ), áp lực thanh toán thấp. Tuy nhiên, lãi suất biến động có thể ảnh hưởng chi phí tài chính.', 'Hàng tồn kho tăng mạnh từ 7.5 tỷ lên 42.3 tỷ, chủ yếu là hàng hóa và chi phí sản xuất dở dang, cho thấy khả năng tích tụ hàng tồn kho. Không trích lập dự phòng giảm giá, cần theo dõi tính thanh khoản và rủi ro lỗi thời.', 5, 'Công ty có kết quả kinh doanh cải thiện rõ rệt (lợi nhuận sau thuế 9.545 tỷ so với lỗ năm trước), hoạt động kinh doanh chính ổn định. Cấu trúc tài chính an toàn với nợ vay ngắn hạn được bao phủ bởi tài sản ngắn hạn. Tuy nhiên, tăng trưởng hàng tồn kho nhanh và giao dịch tập trung vào công ty mẹ là điểm cần lưu ý. Triển vọng trung hạn khả quan nếu quản lý tốt hàng tồn kho và đa dạng hóa khách hàng.'),
('VHF_2017_consolidated', 'VHF', 2017, 'consolidated', 'Giao dịch mua bán với công ty mẹ (Tổng Công ty Lương thực Miền Bắc) và các công ty cùng mẹ có giá trị lớn (tổng cộng hơn 45 tỷ VND). Các giao dịch này thuộc hoạt động kinh doanh chính là thương mại lương thực, chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường. Tuy nhiên, mức độ tập trung vào nhóm liên quan là đáng chú ý.', 'Nợ vay ngắn hạn cuối năm 2017 là 24.553.449.930 VND, giảm mạnh so với đầu năm (57.836.087.668 VND). Tỷ lệ nợ/Vốn chủ sở hữu chỉ 5%, áp lực trả nợ thấp. Các khoản vay chủ yếu tại các ngân hàng lớn với lãi suất thỏa thuận, một khoản vay cá nhân không lãi suất. Một khoản vay tại BIDV Tây Hồ có thế chấp bằng khoản phải thu và hàng tồn kho.', 'Hàng tồn kho giảm mạnh từ 21,18 tỷ VND xuống 7,54 tỷ VND, cho thấy hoạt động luân chuyển hàng hóa tích cực. Hàng tồn kho chủ yếu là hàng hóa và chi phí sản xuất dở dang, không có dự phòng giảm giá. Tuy nhiên, Công ty có một khoản chi phí xây dựng cơ bản dở dang 5,4 tỷ VND, cần theo dõi tiến độ triển khai.', 3, 'Công ty có cấu trúc tài chính tương đối an toàn với tỷ lệ nợ thấp, thanh khoản tốt (tiền và đầu tư ngắn hạn chiếm tỷ trọng lớn). Tuy nhiên, hoạt động kinh doanh chính (thương mại lương thực) đang gặp khó khăn khi lỗ trước thuế 5,7 tỷ VND năm 2017. Ban lãnh đạo có sự thay đổi trong năm, giao dịch với bên liên quan (công ty mẹ) lớn nhưng là hoạt động kinh doanh thông thường. Ý kiến kiểm toán chấp nhận toàn phần.'),
('VHF_2016_consolidated', 'VHF', 2016, 'consolidated', 'Giao dịch với bên liên quan (công ty mẹ và các công ty cùng mẹ) chiếm tỷ trọng lớn trong hoạt động mua bán hàng hóa, nguyên vật liệu. Điều này tạo rủi ro tập trung khách hàng và nhà cung cấp, cũng như rủi ro về giá chuyển nhượng không phản ánh giá thị trường. Các khoản phải thu và phải trả với bên liên quan cũng ở mức đáng kể.', 'Nợ vay ngắn hạn chiếm tỷ trọng cao (57.8 tỷ VND) với hạn mức tín dụng lớn tại các ngân hàng lớn. Áp lực trả nợ ngắn hạn ở mức trung bình. Một khoản vay lớn tại ngân hàng Nông nghiệp không có tài sản đảm bảo, chỉ dựa trên uy tín. Khoản vay tại BIDV có bảo đảm bằng tài sản và bảo lãnh.', 'Hàng tồn kho giảm so với đầu năm (từ 28.8 tỷ xuống 21.2 tỷ VND), cho thấy khả năng luân chuyển hàng hóa cải thiện. Tuy nhiên, vẫn còn một khoản đáng kể là chi phí sản xuất kinh doanh dở dang và hàng hóa. Dự phòng phải thu khó đòi lớn (35.3 tỷ VND) cho thấy rủi ro tín dụng cao với một số khách hàng.', 6, 'Công ty có ý kiến kiểm toán ngoại trừ do chưa ghi nhận đầy đủ chi phí tiền thuê đất và phạt chậm nộp, ảnh hưởng đến lợi nhuận. Hoạt động kinh doanh lỗ ròng trong năm (lợi nhuận trước thuế chỉ 180 triệu VND). Tỷ lệ nợ trên vốn chủ sở hữu ở mức an toàn (23.4%). Tuy nhiên, công ty phụ thuộc lớn vào giao dịch với công ty mẹ và các công ty liên kết, có rủi ro tập trung. Hàng tồn kho giảm nhưng dự phòng phải thu khó đòi lớn. Tình hình tài chính có áp lực nhưng vẫn duy trì được hoạt động liên tục.'),
('VHF_2015_consolidated', 'VHF', 2015, 'consolidated', 'Giao dịch với cổ đông lớn Tổng Công ty Lương thực Miền Bắc (51%) có quy mô đáng kể: doanh thu bán hàng 18.9 tỷ VND và phải trả người bán 3.2 tỷ VND. Đầu tư vào liên doanh FTC-Tungshing 15.1 tỷ VND và nhận cổ tức 3.3 tỷ VND. Các giao dịch này chủ yếu phục vụ hoạt động kinh doanh cốt lõi và đầu tư chiến lược, chưa thấy dấu hiệu chuyển giá hay rút vốn bất thường rõ ràng.', 'Nợ vay ngắn hạn tăng mạnh từ 36.7 tỷ lên 75.9 tỷ VND, chủ yếu vay tại Agribank với thời hạn 12 tháng. Áp lực trả nợ ngắn hạn cao, tuy nhiên Công ty có tiền và tương đương tiền lớn (119 tỷ) và đầu tư ngắn hạn (63 tỷ) đảm bảo thanh khoản. Lãi suất vay theo thỏa thuận, có thể biến động theo thị trường.', 'Hàng tồn kho giảm từ 48.2 tỷ xuống 28.8 tỷ VND, chủ yếu do giảm chi phí sản xuất kinh doanh dở dang. Dự phòng giảm giá hàng tồn kho 0, cho thấy chưa có dấu hiệu giảm giá. Các dự án xây dựng dở dang dài hạn tăng nhẹ nhưng quy mô nhỏ (4.1 tỷ VND), chưa có dấu hiệu đình trệ hay đọng vốn kéo dài.', 5, 'Công ty có sự tăng trưởng mạnh về lợi nhuận sau thuế (từ 1.0 tỷ lên 6.6 tỷ VND) trong năm 2015, tuy nhiên vẫn tồn tại vấn đề về tiền thuê đất chưa hạch toán (20.8 tỷ VND) dẫn đến ý kiến kiểm toán ngoại trừ. Nợ vay ngắn hạn tăng cao nhưng vẫn nằm trong tầm kiểm soát nhờ thanh khoản tốt. Ban lãnh đạo ổn định với cổ đông lớn là Tổng Công ty Lương thực Miền Bắc. Triển vọng trung hạn phụ thuộc vào việc giải quyết dứt điểm khoản tiền thuê đất và duy trì hiệu quả kinh doanh.'),
('VHE_2025_parent', 'VHE', 2025, 'parent', 'Giao dịch với các bên liên quan trong năm 2025 không phát sinh giá trị lớn, chủ yếu là đầu tư vào công ty con đã thực hiện từ năm trước. Các khoản bảo đảm từ người thân của Chủ tịch HĐQT cho vay ngân hàng có thể tiềm ẩn rủi ro nhưng chưa có dấu hiệu bất thường.', 'Nợ vay ngắn hạn chiếm tỷ trọng cao với tổng nợ vay ngắn hạn khoảng 222 tỷ VNĐ, nợ dài hạn 0.42 tỷ VNĐ. Chi phí lãi vay năm 2025 là 13.5 tỷ VNĐ, tạo áp lực đáng kể lên dòng tiền và lợi nhuận. Các khoản vay được đảm bảo bằng hàng tồn kho và quyền sử dụng đất, với nhiều chủ nợ ngân hàng khác nhau.', 'Hàng tồn kho có giá trị lớn 313.8 tỷ VNĐ, chủ yếu là hàng hóa và nguyên liệu. Không có dự phòng giảm giá hàng tồn kho được ghi nhận, cho thấy rủi ro giảm giá có thể chưa được đánh giá đầy đủ, đặc biệt với hàng nông sản có tính thời vụ.', 4, 'Công ty ghi nhận tăng trưởng mạnh về doanh thu và lợi nhuận năm 2025 với lợi nhuận sau thuế đạt 17.3 tỷ VNĐ, tăng gần 14 lần so với năm trước. Tuy nhiên, cấu trúc tài chính có rủi ro cao do nợ vay ngắn hạn lớn và chi phí lãi vay tăng đột biến. Quản trị công ty ở mức trung bình với ý kiến kiểm toán chấp nhận toàn phần nhưng có các giao dịch bảo đảm từ bên liên quan. Triển vọng trung hạn phụ thuộc vào khả năng quản lý nợ và duy trì tăng trưởng kinh doanh.'),
('VHC_2025_consolidated', 'VHC', 2025, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán hàng hóa, dịch vụ phục vụ sản xuất kinh doanh, không có dấu hiệu bất thường. Giá trị giao dịch lớn nhưng thuộc hoạt động cốt lõi.', 'Nợ vay ngắn hạn với lãi suất thỏa thuận, được đảm bảo bằng tài sản như quyền sử dụng đất, TSCĐ và khoản phải thu. Áp lực thanh toán thấp do dòng tiền hoạt động mạnh.', 'Hàng tồn kho được trích lập dự phòng giảm giá, luân chuyển tốt. Các dự án xây dựng dở dang đang trong tiến độ triển khai, không có dấu hiệu đình trệ.', 4, 'Doanh nghiệp có kết quả kinh doanh tăng trưởng, lợi nhuận gộp tăng. Cơ cấu tài chính lành mạnh với tỷ lệ nợ hợp lý. Công tác quản trị rủi ro tốt, ban lãnh đạo nhất quán.'),
('VHC_2025_parent', 'VHC', 2025, 'parent', 'Giao dịch với bên liên quan có quy mô rất lớn: doanh thu bán hàng cho Coast Beacon (liên quan của Chủ tịch HĐQT) đạt 1.622 tỷ VND, chiếm khoảng 28% doanh thu thuần; phải thu cuối kỳ từ Coast Beacon lên tới 959 tỷ VND. Cho vay tín chấp cho các công ty con tổng cộng 1.173 tỷ VND không có tài sản đảm bảo. Có khoản trả trước cho cá nhân liên quan 19,9 tỷ VND và tạm ứng nhân viên 100 tỷ VND dùng cho mục đích nhận chuyển nhượng quyền sử dụng đất. Các giao dịch này tuy nằm trong chuỗi giá trị thủy sản nhưng quy mô lớn và một số khoản thiếu tài sản đảm bảo cần được giám sát chặt chẽ.', 'Nợ vay ngắn hạn tại 2 ngân hàng (Vietcombank và BIDV) tổng cộng 991 tỷ VND, được đảm bảo bằng quyền sử dụng đất, TSCĐ và tiền gửi tiết kiệm 60 tỷ VND. Tỷ lệ nợ vay/vốn chủ sở hữu chỉ khoảng 0,14 lần - mức rất thấp. Công ty đã thanh lý toàn bộ nợ tại ANZ và HSBC trong năm. Áp lực trả nợ ngắn hạn thấp, dòng tiền từ hoạt động kinh doanh đạt 500 tỷ VND/năm đủ khả năng đáp ứng nghĩa vụ nợ.', 'Tổng hàng tồn kho 1.175 tỷ VND, dự phòng giảm giá 75 tỷ VND (tăng 5,6 tỷ so với đầu năm). Hàng hóa bất động sản 219 tỷ VND chưa trích lập dự phòng, đây là điểm rủi ro tiềm ẩn nếu thị trường bất động sản suy giảm. Chi phí sản xuất kinh doanh dở dang 495 tỷ VND (giảm từ 640 tỷ) phản ánh hoạt động nuôi trồng thủy sản đang trong chu kỳ sản xuất. Tỷ lệ dự phòng/tổng hàng tồn kho khoảng 6% ở mức hợp lý cho ngành thủy sản.', 4, 'Công ty Cổ phần Vĩnh Hoàn là doanh nghiệp thủy sản hàng đầu với hoạt động kinh doanh cốt lõi ổn định. Doanh thu thuần năm 2025 đạt 5.723 tỷ VND (giảm 10% so với năm trước) nhưng lợi nhuận sau thuế tăng 30% lên 860 tỷ VND nhờ biên lợi nhuận cải thiện và chi phí tài chính giảm mạnh. Cấu trúc tài chính lành mạnh với tỷ lệ nợ/vốn chủ sở hữu thấp (0,14 lần), dòng tiền hoạt động kinh doanh dương mạnh. Tuy nhiên, cần lưu ý giao dịch với bên liên quan quy mô lớn (đặc biệt với Coast Beacon), các khoản cho vay tín chấp cho công ty con, và hàng hóa bất động sản chưa trích lập dự phòng. Ban lãnh đạo nhất quán, ý kiến kiểm toán chấp nhận toàn phần. Triển vọng trung hạn khả quan nhờ vị thế dẫn đầu ngành và chuỗi giá trị khép kín.'),
('VHE_2024_consolidated', 'VHE', 2024, 'consolidated', 'Giao dịch đầu tư vào công ty con với giá trị lớn 127.5 tỷ VND, thuộc hoạt động mở rộng kinh doanh bình thường. Các bên liên quan khác chủ yếu là gia đình người quản lý, giao dịch chủ yếu là bảo lãnh vay vốn, không có dấu hiệu bất thường hay chuyển giá. Rủi ro thấp.', 'Nợ vay chủ yếu ngắn hạn tại các ngân hàng lớn như MB Bank, VPBank, Maritime Bank với tổng nợ khoảng 124.8 tỷ VND, chiếm tỷ trọng cao trong tổng nợ. Tỷ lệ nợ/VCSH khoảng 0.37, ở mức hợp lý. Chi phí lãi vay năm 2024 là 6.4 tỷ VND, áp lực trả nợ trung bình do nợ ngắn hạn chiếm tỷ trọng lớn và đáo hạn nhanh. Tài sản thế chấp chủ yếu là quyền sử dụng đất, xe ô tô và tài sản công ty con.', 'Hàng tồn kho chủ yếu là hàng hóa thương mại nông sản với giá trị cao 189.6 tỷ VND, chiếm hơn 93% tổng tồn kho. Dự phòng giảm giá hàng tồn kho bằng 0 cho thấy rủi ro thấp, hàng tồn kho luân chuyển nhanh trong hoạt động thương mại xuất khẩu. Không có dự án xây dựng dở dang hay bất động sản đầu tư.', 3, 'Công ty có cấu trúc tài cơ bản ổn định, doanh thu tăng 30% so với năm trước nhờ phục hồi thị trường xuất khẩu. Lợi nhuận sau thuế 1.225 tỷ VND, tăng trưởng dương. Tuy nhiên, áp lực nợ ngắn hạn lớn, chi phí lãi vay chiếm tỷ trọng đáng kể trong lợi nhuận. Ban lãnh đạo có kinh nghiệm, cơ cấu cổ đông tập trung với người đại diện pháp luật là Chủ tịch HĐQT. Triển vọng trung hạn phụ thuộc vào biến động thị trường nông sản và quản lý thanh khoản nợ ngắn hạn.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VHC_2023_parent', 'VHC', 2023, 'parent', 'Rủi ro ở mức trung bình. Công ty có giao dịch mua bán lớn với các công ty con và bên liên quan của Chủ tịch Hội đồng Quản trị, đặc biệt là doanh thu bán hàng với Coast Beacon Inc. (gần 1.721 tỷ VND) và Công ty TNHH MTV Thanh Bình Đồng Tháp (gần 1.077 tỷ VND). Các khoản phải thu của khách hàng từ bên liên quan chiếm tỷ trọng cao (1.074 tỷ VND trên tổng 1.396 tỷ VND). Công ty cũng cho vay ngắn hạn lớn tới các công ty con (tổng dư nợ 1.005 tỷ VND). Tuy nhiên, các giao dịch này phần lớn thuộc hoạt động sản xuất kinh doanh cốt lõi và liên quan trực tiếp đến chuỗi giá trị thủy sản.', 'Rủi ro nợ vay thấp. Nợ ngắn hạn vay ngân hàng là 956 tỷ VND, tập trung tại ba ngân hàng lớn (Vietcombank, ANZ, HSBC) với lãi suất biến động theo từng lần giải ngân. Công ty có tài sản thế chấp là quyền sử dụng đất, TSCĐ, khoản phải thu khách hàng và hàng tồn kho. Tỷ lệ nợ/Vốn chủ sở hữu (~0.14 lần) rất thấp, áp lực trả nợ ngắn hạn không đáng kể. Công ty còn có cam kết bảo lãnh cho vay của các công ty con lên tới hàng nghìn tỷ đồng, tiềm ẩn rủi ro contingent.', 'Rủi ro hàng tồn kho ở mức trung bình. Tổng giá trị hàng tồn kho (sau dự phòng) là 1.807 tỷ VND, tăng so với năm trước. Thành phẩm chiếm tỷ trọng lớn với dự phòng giảm giá 90 tỷ VND. Hàng hóa bất động sản (209 tỷ VND) có thể liên quan đến dự án bất động sản, cần theo dõi thanh khoản. Hàng tồn kho được dùng làm tài sản thế chấp cho vay. Công ty đã hoàn nhập một phần dự phòng giảm giá hàng tồn kho trong năm (72 tỷ VND).', 4, 'Vĩnh Hoàn (VHC) có nền tảng tài chính vững mạnh với tỷ suất lợi nhuận gộp cao (khoảng 11.7%), cơ cấu tài chính an toàn (nợ vay thấp, vốn chủ sở hữu lớn), và dòng tiền từ hoạt động kinh doanh tích cực. Công ty hoạt động chính trong lĩnh vực chế biến thủy sản với chuỗi giá trị tích hợp từ nuôi trồng đến xuất khẩu, tập trung vào thị trường Mỹ. Rủi ro chính đến từ mối quan hệ kinh doanh phức tạp với bên liên quan (chủ yếu là công ty con và công ty liên quan của Chủ tịch HĐQT), các khoản đầu tư tài chính vào chứng khoán và công ty con, cũng như áp lực từ biến động tỷ giá. Ban lãnh đạo có kinh nghiệm và công ty niêm yết minh bạch trên HOSE.'),
('VHC_2023_consolidated', 'VHC', 2023, 'consolidated', 'Giao dịch với bên liên quan có quy mô lớn, đặc biệt doanh thu bán hàng cho Coast Beacon Inc. chiếm khoảng 29.5% tổng doanh thu. Điều này thể hiện sự phụ thuộc vào bên liên quan và có thể tiềm ẩn rủi ro chuyển giá, mặc dù giao dịch thuộc hoạt động kinh doanh thông thường.', 'Nợ vay ngắn hạn tập trung tại các ngân hàng lớn với lãi suất biến động theo từng lần nhận nợ. Tổng nợ vay trên vốn chủ sở hữu ở mức 0.37 lần, áp lực thanh toán ngắn hạn đáng kể nhưng được hỗ trợ bởi tài sản thế chấp là quyền sử dụng đất, TSCĐ và khoản phải thu khách hàng.', 'Hàng tồn kho có giá trị lớn với dự phòng giảm giá khoảng 10%. Khoản chi phí sản xuất kinh doanh dở dang 1.49 nghìn tỷ VND có thể là dự án xây dựng, cần theo dõi tiến độ và nguy cơ đọng vốn. Tuy nhiên, dự phòng đã được trích lập tương đối đầy đủ.', 5, 'Công ty Vĩnh Hoàn là doanh nghiệp thủy sản hàng đầu với cấu trúc tài chính lành mạnh, tỷ lệ nợ vay thấp và thanh khoản tốt. Tuy nhiên, công ty có giao dịch lớn với bên liên quan và nợ vay ngắn hạn cao, đặt ra rủi ro quản trị và lãi suất. Triển vọng trung hạn phụ thuộc vào thị trường xuất khẩu và quản lý chuỗi cung ứng.'),
('VHC_2022_parent', 'VHC', 2022, 'parent', 'Công ty có hệ sinh thái giao dịch bên liên quan rất lớn, bao gồm 8 công ty con và nhiều công ty liên quan khác. Tổng doanh thu bán hàng cho bên liên quan đạt hơn 6.346 tỷ đồng (82.7% doanh thu thuần), trong đó Coast Beacon Inc. chiếm tỷ trọng lớn nhất (3.716 tỷ). Các khoản cho vay ngắn hạn cho công ty con lên tới 2.228 tỷ đồng, trong đó Công ty TNHH Thức ăn Thủy sản Feed One nhận vay 1.418 tỷ. Các khoản phải thu ngắn hạn của khách hàng từ bên liên quan là 1.646 tỷ đồng, chiếm 85.3% tổng phải thu khách hàng. Mức độ phụ thuộc vào bên liên quan rất cao, tuy nhiên các giao dịch chủ yếu phục vụ hoạt động sản xuất kinh doanh cốt lõi (mua bán nguyên liệu, thức ăn thủy sản, chế biến thủy sản) và chưa có dấu hiệu chuyển giá bất thường.', 'Tổng nợ vay ngắn hạn là 855 tỷ đồng, phân bổ tại 3 ngân hàng lớn (VCBank, ANZ, HSBC). Tỷ lệ nợ vay/Vốn chủ sở hữu chỉ khoảng 0.14 lần - mức rất thấp. Công ty không có nợ dài hạn. Lãi suất theo thỏa thuận từng lần giải ngân. Tài sản thế chấp bao gồm quyền sử dụng đất, TSCĐ nhà xưởng, khoản phải thu khách hàng và hàng tồn kho. Áp lực trả nợ ngắn hạn thấp, dòng tiền từ hoạt động kinh doanh đạt 1.367 tỷ đồng - đủ khả năng trả nợ gốc và lãi.', 'Tổng hàng tồn kho là 1.470 tỷ đồng (giá trị ghi sổ sau dự phòng). Dự phòng giảm giá hàng tồn kho tăng mạnh từ 37.5 tỷ lên 163.5 tỷ đồng trong năm, phản ánh thành phẩm có giá trị thuần có thể thực hiện thấp hơn giá gốc. Hàng hóa bất động sản 93.7 tỷ chưa trích lập dự phòng. Chi phí xây dựng cơ bản dở dang 88.7 tỷ đồng bao gồm nhà ở cho người lao động và ao nuôi cá - các dự án này đã giảm so với năm trước (từ 110.5 tỷ), cho thấy tiến độ triển khai hợp lý. Hàng tồn kho có 206.5 tỷ và 93.64 tỷ đồng đã được thế chấp cho ngân hàng.', 4, 'Công ty Cổ phần Vĩnh Hoàn có kết quả kinh doanh tăng trưởng mạnh năm 2022: doanh thu thuần đạt 7.671 tỷ đồng (tăng 36.7%), lợi nhuận sau thuế đạt 1.340 tỷ đồng (tăng 19.3%). Cấu trúc tài chính lành mạnh với tỷ lệ nợ vay/VCSH rất thấp (0.14 lần), dòng tiền hoạt động kinh doanh dồi dào (1.367 tỷ). Ý kiến kiểm toán chấp nhận toàn phần từ PwC. Điểm đáng lưu ý là mức độ phụ thuộc lớn vào giao dịch bên liên quan (doanh thu bán hàng cho bên liên quan chiếm 82.7%), nhưng đây là đặc thù của mô hình tập đoàn với chuỗi giá trị tích hợp dọc trong ngành thủy sản. Công ty duy trì chính sách cổ tức tốt (366.7 tỷ năm 2022) và có hệ thống công ty con hoạt động hiệu quả.'),
('VHC_2022_consolidated', 'VHC', 2022, 'consolidated', 'Giao dịch với bên liên quan có quy mô lớn, đặc biệt doanh thu bán hàng cho Coast Beacon Inc. chiếm tỷ trọng cao (hơn 43% doanh thu thuần). Điều này tạo rủi ro tập trung khách hàng và phụ thuộc vào bên liên quan. Tuy nhiên, các giao dịch mua bán thuộc hoạt động kinh doanh chính và chưa thấy dấu hiệu chuyển giá bất thường.', 'Nợ vay ngắn hạn ở mức cao (khoảng 2,2 nghìn tỷ VNĐ) với lãi suất biến động theo thị trường, gây áp lực thanh toán và chi phí lãi vay. Nợ dài hạn thấp hơn nhưng vẫn có tài sản thế chấp lớn (quyền sử dụng đất, máy móc, phải thu khách hàng). Tỷ lệ nợ/VCSH khoảng 0.5 lần ở mức an toàn nhưng cần theo dõi áp lực thanh khoản ngắn hạn.', 'Hàng tồn kho tăng mạnh, đặc biệt thành phẩm dự phòng giảm giá tăng vọt từ 87 tỷ lên 396 tỷ VNĐ, cho thấy nguy cơ hàng hóa chậm luân chuyển hoặc giảm giá. Chi phí xây dựng dở dang tồn đọng lớn, có thể ảnh hưởng đến dòng tiền và hiệu quả đầu tư.', 5, 'Doanh nghiệp có tăng trưởng doanh thu và lợi nhuận mạnh năm 2022, nhưng đi kèm rủi ro về tập trung khách hàng liên quan, áp lực nợ ngắn hạn và hàng tồn kho tích tụ. Ban lãnh đạo nhất quán, kiểm toán không có vấn đề lớn. Triển vọng phụ thuộc vào khả năng quản lý rủi ro tài chính và tối ưu hóa chuỗi cung ứng.'),
('VHC_2021_consolidated', 'VHC', 2021, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là Công ty liên quan của Chủ tịch Hội đồng Quản trị và công ty liên kết, với tổng doanh thu bán hàng khoảng 38,5 tỷ VNĐ và mua hàng khoảng 120,3 tỷ VNĐ trong năm 2021. Các giao dịch này chiếm tỷ trọng nhỏ trong tổng doanh thu và chi phí, nhưng cần theo dõi để đảm bảo tính minh bạch và giá thị trường. Rủi ro trung bình.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn với tổng dư nợ hơn 1,723 tỷ VNĐ, chủ yếu từ các ngân hàng thương mại lớn. Nợ dài hạn khoảng 156,4 tỷ VNĐ. Công ty sử dụng nhiều tài sản thế chấp như khoản phải thu khách hàng, hàng tồn kho, quyền sử dụng đất và TSCĐ. Áp lực trả nợ ngắn hạn cao, nhưng Công ty có dòng tiền kinh doanh dương và tài sản đảm bảo đầy đủ. Rủi ro nợ ở mức trung bình đến cao.', 'Hàng tồn kho có tổng giá trị ghi sổ khoảng 1,880 tỷ VNĐ, với dự phòng giảm giá 87 tỷ VNĐ (tỷ lệ dự phòng khoảng 4,6%). Hàng tồn kho chủ yếu là thành phẩm và chi phí SXKD dở dang, phù hợp với hoạt động sản xuất thủy sản. Dự phòng giảm giá đã được trích lập tương đối, cho thấy sự thận trọng. Tuy nhiên, cần theo dõi tính thanh khoản của hàng tồn kho, đặc biệt là nguyên vật liệu và thành phẩm. Rủi ro thấp đến trung bình.', 5, 'Công ty Vĩnh Hoàn có kết quả kinh doanh tăng trưởng mạnh với doanh thu thuần năm 2021 đạt 9,054 tỷ VNĐ, tăng 28,6% so với năm trước, và lợi nhuận sau thuế đạt 1,106 tỷ VNĐ, tăng 53,8%. Tuy nhiên, nợ vay tăng đáng kể để tài trợ cho hoạt động đầu tư và mở rộng, dẫn đến áp lực tài chính. Cơ cấu cổ đông rõ ràng, ban lãnh đạo ổn định, và kiểm toán viên đưa ra ý kiến chấp nhận toàn phần. Công ty có các giao dịch với bên liên quan nhưng quy mô còn hạn chế. Nhìn chung, tình hình tài chính lành mạnh, nhưng cần quản lý rủi ro nợ và tối ưu hóa chuỗi cung ứng. Triển vọng trung hạn khả quan do ngành thủy sản có tiềm năng tăng trưởng.'),
('AAA_2024_consolidated', 'AAA', 2024, 'consolidated', 'Giao dịch cho vay nội bộ đáng lưu ý', 'Áp lực trả nợ trái phiếu lớn', 'Hàng tồn kho ứ đọng nhiều', 8, 'Doanh nghiệp có rủi ro thanh khoản cao');
PRAGMA foreign_keys = ON;
